import{_ as e,o as r,c as a,ae as o}from"./chunks/framework.BdQd5MxT.js";const g=JSON.parse('{"title":"NVIDIA 工程实践深度分析：Extreme Co-Design 与 MLPerf 推理记录","description":"","frontmatter":{},"headers":[],"relativePath":"bestpractice/nvidia-inference-extreme-codesign.md","filePath":"bestpractice/nvidia-inference-extreme-codesign.md"}'),d={name:"bestpractice/nvidia-inference-extreme-codesign.md"};function n(i,t,l,s,h,c){return r(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="nvidia-工程实践深度分析-extreme-co-design-与-mlperf-推理记录" tabindex="-1">NVIDIA 工程实践深度分析：Extreme Co-Design 与 MLPerf 推理记录 <a class="header-anchor" href="#nvidia-工程实践深度分析-extreme-co-design-与-mlperf-推理记录" aria-label="Permalink to &quot;NVIDIA 工程实践深度分析：Extreme Co-Design 与 MLPerf 推理记录&quot;">​</a></h1><blockquote><p>分析来源：</p><ol><li><a href="https://developer.nvidia.com/blog/nvidia-platform-delivers-lowest-token-cost-enabled-by-extreme-co-design/" target="_blank" rel="noreferrer">NVIDIA Platform Delivers Lowest Token Cost Enabled by Extreme Co-Design</a> (2026-04-03)</li><li><a href="https://blogs.nvidia.com/blog/gtc-2026-news/" target="_blank" rel="noreferrer">NVIDIA GTC 2026 Live Updates</a> (2026-04)</li></ol><p>分析师：WLB 分析日期：2026-04-10</p></blockquote><hr><h2 id="part-1-核心数据与关键成就" tabindex="-1">Part 1: 核心数据与关键成就 <a class="header-anchor" href="#part-1-核心数据与关键成就" aria-label="Permalink to &quot;Part 1: 核心数据与关键成就&quot;">​</a></h2><h3 id="mlperf-inference-v6-0-成绩单" tabindex="-1">MLPerf Inference v6.0 成绩单 <a class="header-anchor" href="#mlperf-inference-v6-0-成绩单" aria-label="Permalink to &quot;MLPerf Inference v6.0 成绩单&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Benchmark</th><th>成绩</th><th>意义</th></tr></thead><tbody><tr><td>DeepSeek-R1 (Offline)</td><td>2,494,310 tokens/sec</td><td>推理吞吐标杆</td></tr><tr><td>GPT-OSS-120B (Server)</td><td>1,096,770 tokens/sec</td><td>MoE 推理能力</td></tr><tr><td>Qwen3-VL-235B (Offline)</td><td>79 samples/sec</td><td>首个多模态 MLPerf 测试</td></tr><tr><td>DLRMv3 (Server)</td><td>99,997 queries/sec</td><td>生成式推荐系统</td></tr></tbody></table><p>累计 MLPerf 训练+推理获胜：<strong>291 次</strong>，是其他所有厂商合计的 <strong>9 倍</strong>。</p><h3 id="gb300-nvl72-半年性能翻-2-7-倍" tabindex="-1">GB300 NVL72 半年性能翻 2.7 倍 <a class="header-anchor" href="#gb300-nvl72-半年性能翻-2-7-倍" aria-label="Permalink to &quot;GB300 NVL72 半年性能翻 2.7 倍&quot;">​</a></h3><p>关键数据点：</p><ul><li>6 个月前首发 DeepSeek-R1 → 今天同样硬件 <strong>2.7x 性能提升</strong></li><li>相同 GB300 NVL72 基础设施和功耗，<strong>2.7x 更多 tokens</strong></li><li><strong>Token 生产成本降低 60%+</strong></li><li>达成方：NVIDIA 合作伙伴 Nebius</li></ul><p><strong>为什么这个数字重要？</strong> 硬件没换，6 个月软件优化让 token 成本腰斩。这不是芯片升级红利，而是<strong>全栈软件工程的胜利</strong>。对 AI Factory 运营商来说，这意味着用同样的电费和硬件成本，营收能力提升 2.7 倍。</p><hr><h2 id="part-2-extreme-co-design-架构解析" tabindex="-1">Part 2: Extreme Co-Design 架构解析 <a class="header-anchor" href="#part-2-extreme-co-design-架构解析" aria-label="Permalink to &quot;Part 2: Extreme Co-Design 架构解析&quot;">​</a></h2><h3 id="什么是-extreme-co-design" tabindex="-1">什么是 Extreme Co-Design <a class="header-anchor" href="#什么是-extreme-co-design" aria-label="Permalink to &quot;什么是 Extreme Co-Design&quot;">​</a></h3><p>传统硬件采购思维：先有芯片 → 再做软件优化 → 性能打折扣。</p><p>NVIDIA 的思路：<strong>从第一天起，硬件+软件+模型三位一体协同设计</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>芯片设计 ←→ 推理软件栈 ←→ 模型架构</span></span>
<span class="line"><span>    ↑___________↓____________↑</span></span>
<span class="line"><span>         三角协同</span></span></code></pre></div><p>黄仁勋原话：&quot;extreme codesign is designing software and silicon in tandem&quot;（软硬件协同设计）。</p><h3 id="关键受益-老显卡永不过时" tabindex="-1">关键受益：老显卡永不过时 <a class="header-anchor" href="#关键受益-老显卡永不过时" aria-label="Permalink to &quot;关键受益：老显卡永不过时&quot;">​</a></h3><p>公告里提到：&quot;NVIDIA GPUs introduced years ago can remain productive, at high utilization rates, in the cloud.&quot;</p><p>这意味着 Blackwell 架构发布时的老卡，可以通过软件更新持续获得性能提升——只要底层芯片架构兼容。</p><p><strong>对我们 OpenClaw 的启发：</strong> 我们用的大多数硬件可能都是&quot;老&quot;卡。如果 NVIDIA 能通过软件栈持续优化旧硬件，我们也应该持续投资 OpenClaw 的推理优化层。</p><hr><h2 id="part-3-tensorrt-llm-软件更新细节" tabindex="-1">Part 3: TensorRT-LLM 软件更新细节 <a class="header-anchor" href="#part-3-tensorrt-llm-软件更新细节" aria-label="Permalink to &quot;Part 3: TensorRT-LLM 软件更新细节&quot;">​</a></h2><h3 id="做了什么优化" tabindex="-1">做了什么优化 <a class="header-anchor" href="#做了什么优化" aria-label="Permalink to &quot;做了什么优化&quot;">​</a></h3><p>本轮 MLPerf v6.0 的性能提升主要来自 <strong>TensorRT-LLM</strong> 软件更新，包括：</p><table tabindex="0"><thead><tr><th>优化维度</th><th>说明</th></tr></thead><tbody><tr><td><strong>Kernel 融合</strong></td><td>合并多个独立操作减少内存访问</td></tr><tr><td><strong>动态批处理</strong></td><td>变长序列的智能打包</td></tr><tr><td><strong>Paged KV Cache</strong></td><td>减少内存碎片，提升 GPU 利用率</td></tr><tr><td><strong>FP8/BF16 混合精度</strong></td><td>精度与吞吐的平衡</td></tr><tr><td><strong>通信重叠</strong></td><td>MoE 专家路由与通信并行</td></tr></tbody></table><h3 id="moe-推理的特别挑战" tabindex="-1">MoE 推理的特别挑战 <a class="header-anchor" href="#moe-推理的特别挑战" aria-label="Permalink to &quot;MoE 推理的特别挑战&quot;">​</a></h3><p>DeepSeek-R1 是稀疏 MoE（Mixture of Experts）：</p><ul><li>总参数大但激活参数小</li><li><strong>瓶颈在专家路由和跨 GPU 通信</strong>，不是计算</li><li>TensorRT-LLM 的 MoE 优化需要特殊的 <strong>all-to-all 通信调度</strong></li></ul><p><strong>OpenClaw 借鉴点：</strong> 如果我们自己跑 MoE 模型（如 Qwen、DeepSeek），专家路由是性能关键点。需要确保网络带宽（NVLink vs PCIe）足够，不然跨 GPU 通信会拖死。</p><hr><h2 id="part-4-新增-benchmark-工作负载解析" tabindex="-1">Part 4: 新增 Benchmark 工作负载解析 <a class="header-anchor" href="#part-4-新增-benchmark-工作负载解析" aria-label="Permalink to &quot;Part 4: 新增 Benchmark 工作负载解析&quot;">​</a></h2><h3 id="新增模型-mlperf-v6-0" tabindex="-1">新增模型（MLPerf v6.0） <a class="header-anchor" href="#新增模型-mlperf-v6-0" aria-label="Permalink to &quot;新增模型（MLPerf v6.0）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>类型</th><th>意义</th></tr></thead><tbody><tr><td><strong>DeepSeek-R1 Interactive</strong></td><td>推理 LLM，稀疏 MoE</td><td>新增交互场景，5x 更快首 token，1.3x 短延迟</td></tr><tr><td><strong>Qwen3-VL-235B</strong></td><td>视觉-语言模型</td><td>首个多模态 MLPerf 测试，235B 参数</td></tr><tr><td><strong>GPT-OSS-120B</strong></td><td>MoE 推理 LLM</td><td>OpenAI 的开源推理模型</td></tr><tr><td><strong>Wan-2.2-T2V-A14B</strong></td><td>文生视频</td><td>4B 参数，测试新的生成式 AI 场景</td></tr><tr><td><strong>DLRMv3</strong></td><td>生成式推荐</td><td>Transformer 架构替代原有 DCNv2</td></tr></tbody></table><h3 id="多模态成为新标准" tabindex="-1">多模态成为新标准 <a class="header-anchor" href="#多模态成为新标准" aria-label="Permalink to &quot;多模态成为新标准&quot;">​</a></h3><p>Qwen3-VL 的加入意义重大——<strong>首个视觉-语言模型进入 MLPerf 推理套件</strong>。这意味着：</p><ul><li>VLM 推理已经成为主流场景</li><li>纯语言模型的推理优化已经成熟</li><li>下一波优化重点是<strong>多模态融合</strong></li></ul><hr><h2 id="part-5-partner-ecosystem-合作伙伴生态" tabindex="-1">Part 5: Partner Ecosystem（合作伙伴生态） <a class="header-anchor" href="#part-5-partner-ecosystem-合作伙伴生态" aria-label="Permalink to &quot;Part 5: Partner Ecosystem（合作伙伴生态）&quot;">​</a></h2><h3 id="_14-家合作伙伴提交-mlperf" tabindex="-1">14 家合作伙伴提交 MLPerf <a class="header-anchor" href="#_14-家合作伙伴提交-mlperf" aria-label="Permalink to &quot;14 家合作伙伴提交 MLPerf&quot;">​</a></h3><p>这是历史最大规模合作伙伴参与：ASUS, Cisco, CoreWeave, Dell, GigaComputing, Google Cloud, HPE, Lenovo, Nebius, Netweb, QCT, Red Hat, Supermicro, Lambda。</p><p><strong>生态策略观察：</strong></p><ul><li>NVIDIA 不自己做所有优化，而是提供底层优化工具（TensorRT-LLM）</li><li>合作伙伴在基础上做自己的定制优化</li><li>结果：全行业围绕 NVIDIA 生态卷，NVIDIA 是最大赢家</li></ul><p><strong>对比 OpenClaw：</strong> 我们没有 NVIDIA 那样的生态护城河。但思路可以学——<strong>提供标准化的 Skill 接口，让社区帮你优化</strong>。SKILL.md 就是我们的 &quot;TensorRT&quot;——别人写的 skill 可以在我们平台跑。</p><hr><h2 id="part-6-战略启示" tabindex="-1">Part 6: 战略启示 <a class="header-anchor" href="#part-6-战略启示" aria-label="Permalink to &quot;Part 6: 战略启示&quot;">​</a></h2><h3 id="ai-factory-的经济学" tabindex="-1">AI Factory 的经济学 <a class="header-anchor" href="#ai-factory-的经济学" aria-label="Permalink to &quot;AI Factory 的经济学&quot;">​</a></h3><p>NVIDIA 的核心论点：<strong>Token Cost = AI Factory 的核心竞争要素</strong></p><ul><li>不是 GPU 数量，不是峰值 FLOPS</li><li>而是<strong>每 token 成本 × 每秒吞吐</strong></li></ul><p>当 token 成本降低 60%，相同定价下利润率暴涨。或者相同利润率下，定价可以更有竞争力。</p><h3 id="对-ai-应用开发者的影响" tabindex="-1">对 AI 应用开发者的影响 <a class="header-anchor" href="#对-ai-应用开发者的影响" aria-label="Permalink to &quot;对 AI 应用开发者的影响&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变化</th><th>影响</th></tr></thead><tbody><tr><td>Token 成本下降</td><td>AI 原生应用可以更便宜，对价格敏感场景（客服、教育）更可行</td></tr><tr><td>推理速度提升</td><td>实时交互场景（语音助手、Copilot）体验更好</td></tr><tr><td>多模态普及</td><td>应用可以原生支持图像+视频+音频，不只是文本</td></tr></tbody></table><h3 id="extreme-co-design-的深层逻辑" tabindex="-1">Extreme Co-Design 的深层逻辑 <a class="header-anchor" href="#extreme-co-design-的深层逻辑" aria-label="Permalink to &quot;Extreme Co-Design 的深层逻辑&quot;">​</a></h3><p><strong>为什么其他厂商追不上？</strong></p><p>黄仁勋的逻辑：</p><ol><li>自己做芯片 + 软件 + 模型 → 三者紧耦合 → 极限优化</li><li>外包芯片/软件/模型 → 接口损耗 → 永远有 gap</li></ol><p>这对 AI 系统设计有普遍意义：<strong>组件之间的接口损耗是性能杀手</strong>。</p><p>对我们自己系统的反思：OpenClaw 的 Gateway 和 Agent 之间的接口，是否有隐性的序列化和反序列化开销？Session 状态的跨进程传递是否有不必要的拷贝？这些&quot;接口损耗&quot;可能比算法优化更影响整体性能。</p><hr><h2 id="part-7-对我们的借鉴" tabindex="-1">Part 7: 对我们的借鉴 <a class="header-anchor" href="#part-7-对我们的借鉴" aria-label="Permalink to &quot;Part 7: 对我们的借鉴&quot;">​</a></h2><h3 id="可行动项" tabindex="-1">可行动项 <a class="header-anchor" href="#可行动项" aria-label="Permalink to &quot;可行动项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>行动项</th><th>来源</th><th>优先级</th></tr></thead><tbody><tr><td>N1</td><td>测量 OpenClaw 实际推理吞吐和延迟（不只是 token 速度，而是端到端响应）</td><td>黄仁勋&quot;测真正重要的&quot;</td><td>P1</td></tr><tr><td>N2</td><td>检查跨进程通信路径，消除不必要的序列化</td><td>接口损耗思维</td><td>P2</td></tr><tr><td>N3</td><td>如果跑 MoE 模型，确认 NVLink 带宽足够</td><td>MoE 通信瓶颈</td><td>P2</td></tr><tr><td>N4</td><td>关注多模态 Skill 机会（VLM 推理）</td><td>Qwen3-VL 进入 MLPerf</td><td>P3</td></tr></tbody></table><h3 id="基础设施对比" tabindex="-1">基础设施对比 <a class="header-anchor" href="#基础设施对比" aria-label="Permalink to &quot;基础设施对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>能力</th><th>NVIDIA</th><th>OpenClaw（当前）</th><th>差距</th></tr></thead><tbody><tr><td>全栈协同设计</td><td>芯片+软件+模型</td><td>Gateway+Agent+Skills</td><td>🔴 大</td></tr><tr><td>软件持续优化旧硬件</td><td>TensorRT-LLM 更新</td><td>少有</td><td>🟡 中</td></tr><tr><td>MoE 推理优化</td><td>原生支持</td><td>需手动配置</td><td>🔴 大</td></tr><tr><td>多模态推理</td><td>行业领先</td><td>无原生支持</td><td>🔴 大</td></tr><tr><td>Partner 生态</td><td>14+ 合作伙伴</td><td>社区 Skills（早起）</td><td>🟡 中</td></tr></tbody></table><hr><h2 id="附录-gtc-2026-配套信息" tabindex="-1">附录：GTC 2026 配套信息 <a class="header-anchor" href="#附录-gtc-2026-配套信息" aria-label="Permalink to &quot;附录：GTC 2026 配套信息&quot;">​</a></h2><ul><li><strong>Vera Rubin</strong>：下一代全栈计算平台，7 芯片 / 5 机架系统 / 1 超算，专为 Agentic AI</li><li><strong>AI Grids</strong>：电信运营商在做地理分布式推理优化</li><li><strong>Jetson Thor</strong>：OpenClaw 在 NVIDIA Jetson Thor 上本地运行，Nemotron 模型 + vLLM</li></ul><hr><p><em>分析完成，2026-04-10 by WLB</em></p>`,70)])])}const b=e(d,[["render",n]]);export{g as __pageData,b as default};
